interface IconProps {
  name: string
  size?: number | string
  style?: React.CSSProperties
  className?: string
}

/**
 * Inline SVG icon component — drop-in replacement for Bootstrap icon <i> tags.
 * Usage: <Icon name="bi-folder2-open" size={16} style={{ marginRight: 6 }} />
 */
export default function Icon({ name, size = 16, style, className }: IconProps) {
  const entry = ICONS[name]
  if (!entry) {
    if (import.meta.env.DEV) {
      console.warn('[Icon] unknown icon:', name)
    }
    return null
  }
  const inner   = typeof entry === 'string' ? entry : entry.content
  const viewBox = typeof entry === 'string' ? '0 0 16 16' : entry.viewBox
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      fill="currentColor"
      viewBox={viewBox}
      aria-hidden="true"
      focusable="false"
      style={{ display: 'inline-block', verticalAlign: '-0.125em', flexShrink: 0, ...style }}
      className={className}
      dangerouslySetInnerHTML={{ __html: inner }}
    />
  )
}
